; 森の城塞

name = 森の城塞３Ｆ
insideName = ３Ｆ
lower = 森の城塞２Ｆ
upper = 森の城塞４Ｆ
level = 23
bgm = eerie
margin = 3
roof = stone
shadow = dark
sky = forest

; 各パーツ
━ = stoner
　 = marble
毒 = poison
／ = door
︻ = panel
㊤ = ladderu
㊦ = ladderd
⑶ = barrel

; 敵情報
maxGroups = 2
monsters = クレリック,アコライト,ハイプリースト,ディサイプル,アルケミスト

; 宝箱
box[1] = 罠はない,信徒の称号・月
box[2] = 罠はない,信徒の称号・星
box[3] = 罠はない,信徒の称号・雲
box[4] = 罠はない

[map]
