[correct]

for(var i = 1; i <= 7; i++) pos[7][i].f.antiWarp = pos[8][i].f.antiWarp = pos[9][i].f.antiWarp = true;
for(var i = 2; i <= 7; i++) pos[7][i].f.eraseMagic = pos[8][i].f.eraseMagic = pos[9][i].f.eraseMagic = true;
for(var i = 3; i <= 7; i++) pos[4][i].f.img = "pond";
pos[4][8].f.antiWarp = pos[4][9].f.antiWarp = true;
pos[1][9].event = 4;
pos[4][2].event = 10;

[endmap]
